1	<template>
2	  <div class="list-content-wrapper">
3	    <a-spin :spinning="permissionStore.spinning">
4	      <div class="wrapper">
5	        <div class="wrapper-title">
6	          <span class="title-icon"></span>
7	          <span>基本信息</span>
8	        </div>
9	        <basic ref="basicRef" :params="formState" />
10	      </div>
11	      <div class="wrapper">
12	        <div class="wrapper-title">
13	          <span class="title-icon"></span>
14	          <span>实例容器配置</span>
15	        </div>
16	        <example ref="exampleRef" :params="formState" />
17	      </div>
18	      <div class="footer">
19	        <a-button style="margin-right: 8px" @click="handleCancel">取消</a-button>
20	        <a-button type="primary" @click="handleSubmit">保存</a-button>
21	      </div>
22	    </a-spin>
23	  </div>
24	</template>
25	
26	<script setup lang="ts">
27	import { ref, onMounted } from 'vue'
28	import basic from './components/basic.vue'
29	import example from '../customManage/components/example.vue'
30	import { useRoute, useRouter } from 'vue-router'
31	import { usePermissionStore } from '@/store/modules/permission'
32	import { message } from 'ant-design-vue'
33	import { createInferenceServing, getInferenceServingDetail, updateInferenceServing } from '@/services/api/operationManage/inferenceService'
34	
35	const permissionStore = usePermissionStore()
36	const route = useRoute()
37	const router = useRouter()
38	
39	const basicRef = ref()
40	const exampleRef = ref()
41	
42	const createDefaultTasks = () => ([
43	  {
44	    key: '1',
45	    name: 'task1',
46	    replicas: '',
47	    hostNetwork: false,
48	    containers: [
49	      {
50	        key: '1',
51	        name: 'container1',
52	        replicas: '',
53	        imageConfig: {
54	          imageType: 'custom',
55	          repositoryId: null,
56	          imageCascader: [],
57	          domain: '',
58	          project: '',
59	          imageName: '',
60	        },
61	        imagePullPolicy: 'IfNotPresent',
62	        commandShell: '',
63	        commandText: '',
64	        environmentVarsData: [{ key: '', value: '' }],
65	        ports: [],
66	        privileged: false,
67	        cpu: '',
68	        memory: '',
69	        storage: [{ storagePoolId: 0, storageType: null, storagePath: '', mountPath: '' }],
70	      },
71	    ],
72	  },
73	])
74	
75	const formState = ref({
76	  name: '',
77	  inferenceFramework: null as string | null,
78	  modelPort: null as number | null,
79	  replicas: null as number | null,
80	  servingType: 'VolcanoJob',
81	  type: 'VolcanoJob', // 兼容容器配置组件
82	  clusterCode: null as string | null,
83	  queueId: null as string | null,
84	  queueName: null as string | null,
85	  labelData: [{ key: '', value: '' }],
86	  annotateData: [{ key: '', value: '' }],
87	  maxRetry: 1,
88	  minAvailable: '',
89	  pluginsData: [{ key: null, value: '' }],
90	  selectedQueueResource: null as any,
91	  tasks: createDefaultTasks(),
92	})
93	
94	const initialiseCommands = () => {
95	  formState.value.tasks.forEach((task: any) => {
96	    task.containers?.forEach((container: any) => {
97	      if (!container.commandShell) container.commandShell = '/bin/bash'
98	      if (!container.commandText) container.commandText = 'sleep 3000'
99	    })
100	  })
101	}
102	
103	onMounted(async () => {
104	  if (route.params.title === '编辑') {
105	    permissionStore.spinning = true
106	    await getInferenceDetail()
107	  } else {
108	    initialiseCommands()
109	  }
110	})
111	
112	const getInferenceDetail = async () => {
113	  try {
114	    const res: any = await getInferenceServingDetail(permissionStore.curProject, route.query.id)
115	    if (res.code !== '00000') return
116	    const data = res.respBody || {}
117	    const volcanoJob = data.volcanoJob || {}
118	
119	    formState.value.name = data.modelName || ''
120	    formState.value.inferenceFramework = data.inferenceFramework || null
121	    formState.value.modelPort = data.modelPort ? Number(data.modelPort) : null
122	    formState.value.replicas = data.replicas !== undefined && data.replicas !== null
123	      ? Number(data.replicas)
124	      : null
125	    formState.value.servingType = data.servingType || 'VolcanoJob'
126	    formState.value.type = formState.value.servingType
127	    formState.value.clusterCode = data.clusterCode || ''
128	    formState.value.queueName = data.queueName || ''
129	
130	    await basicRef.value?.handleClusterChange(data.clusterCode)
131	    await basicRef.value?.handleQueueChange(data.queueName)
132	    await exampleRef.value?.getCustomData(volcanoJob)
133	
134	    formState.value.maxRetry = volcanoJob.maxRetry ?? 1
135	    formState.value.minAvailable = volcanoJob.minAvailable ?? ''
136	
137	    formState.value.labelData = volcanoJob.labels
138	      ? Object.entries(volcanoJob.labels).map(([key, value]) => ({ key, value: String(value) }))
139	      : [{ key: '', value: '' }]
140	
141	    formState.value.annotateData = volcanoJob.annotations
142	      ? Object.entries(volcanoJob.annotations).map(([key, value]) => ({ key, value: String(value) }))
143	      : [{ key: '', value: '' }]
144	
145	    formState.value.pluginsData = volcanoJob.plugins
146	      ? Object.entries(volcanoJob.plugins).map(([key, value]) => ({ key, value: String(value) })) || [{ key: null, value: '' }]
147	      : [{ key: null, value: '' }]
148	
149	    formState.value.tasks = Array.isArray(volcanoJob.tasks) && volcanoJob.tasks.length
150	      ? volcanoJob.tasks
151	      : createDefaultTasks()
152	
153	    formState.value.tasks.forEach((task: any, taskIndex: number) => {
154	      task.key = String(taskIndex + 1)
155	      task.containers?.forEach((container: any, containerIndex: number) => {
156	        container.key = String(containerIndex + 1)
157	
158	        if (container.environmentVars && typeof container.environmentVars === 'object') {
159	          container.environmentVarsData = Object.entries(container.environmentVars).map(([key, value]) => ({
160	            key,
161	            value: String(value),
162	          }))
163	        } else {
164	          container.environmentVarsData = [{ key: '', value: '' }]
165	        }
166	
167	        if (container.imageConfig) {
168	          container.imageConfig.imageType = container.imageConfig.project === 'preset-job-images' ? 'preset' : 'custom'
169	          container.imageConfig.imageCascader = [container.imageConfig.project, container.imageConfig.imageName]
170	        }
171	
172	        container.cpu = container.cpu ? Number(container.cpu) : ''
173	        container.memory = container.memory ? Number(container.memory) : ''
174	        container.gpu = container.gpu ? Number(container.gpu) : ''
175	
176	        if (Array.isArray(container.command)) {
177	          container.commandShell = container.command[0] || ''
178	          container.commandText = container.command.length >= 3 ? (container.command[2] || '') : ''
179	        } else {
180	          container.commandShell = container.commandShell || ''
181	          container.commandText = container.commandText || ''
182	        }
183	
184	        if (Array.isArray(container.storage)) {
185	          container.storage = container.storage.map((item: any) => {
186	            const storageType = item.StorageType === 'hostPath'
187	              ? 'hostPath'
188	              : item.StorageType === 'tdsc'
189	                ? 'tdsc'
190	                : ''
191	
192	            let displayStoragePath = item.storagePath || ''
193	            if (displayStoragePath.startsWith('/')) displayStoragePath = displayStoragePath.slice(1)
194	
195	            return {
196	              storagePoolId: item.storagePoolId == 0 ? [] : [item.storagePoolId ? Number(item.storagePoolId) : 0, displayStoragePath],
197	              storageType,
198	              storagePath: displayStoragePath,
199	              mountPath: item.mountPath || '',
200	            }
201	          })
202	        }
203	      })
204	    })
205	  } finally {
206	    permissionStore.spinning = false
207	  }
208	}
209	
210	const validateKeyValue = (list: any[], typeLabel: string) => {
211	  for (const [index, item] of list.entries()) {
212	    const hasKey = item.key && item.key.trim() !== ''
213	    const hasValue = item.value && item.value.trim() !== ''
214	    if (hasValue && !hasKey) {
215	      message.error(`请完善第${index + 1}个${typeLabel}的配置：输入key值`)
216	      return false
217	    }
218	  }
219	  return true
220	}
221	
222	const validateEnvironmentVars = (vars: any[]) => {
223	  const keySet = new Set()
224	  for (const [index, item] of vars.entries()) {
225	    const hasKey = item.key && item.key.trim() !== ''
226	    const hasValue = item.value && item.value.trim() !== ''
227	    if (hasKey && !hasValue) {
228	      message.error(`请完善第${index + 1}个环境变量的配置：输入value值`)
229	      return false
230	    }
231	    if (hasValue && !hasKey) {
232	      message.error(`请完善第${index + 1}个环境变量的配置：输入key值`)
233	      return false
234	    }
235	    if (hasKey) {
236	      const trimmedKey = item.key.trim()
237	      if (keySet.has(trimmedKey)) {
238	        message.error(`环境变量 key 存在重复：${trimmedKey}`)
239	        return false
240	      }
241	      keySet.add(trimmedKey)
242	    }
243	  }
244	  return true
245	}
246	
247	const hasDuplicateProperty = (arr: any[], key: string) => {
248	  const seen = new Set()
249	  for (const item of arr) {
250	    if (item[key] !== undefined) {
251	      if (seen.has(item[key])) return true
252	      seen.add(item[key])
253	    }
254	  }
255	  return false
256	}
257	
258	const validatePorts = (ports: any[]) => {
259	  if (!Array.isArray(ports) || !ports.length) return true
260	  const nameRegex = /^[a-z][a-z0-9-]{0,14}$/
261	  for (const port of ports) {
262	    if (!port.containerPort) {
263	      message.error('请输入容器端口')
264	      return false
265	    }
266	    if (!port.name) {
267	      message.error('请输入端口名')
268	      return false
269	    }
270	    if (!port.protocol) {
271	      message.error('请选择通信方式')
272	      return false
273	    }
274	    if (!nameRegex.test(port.name)) {
275	      message.error('端口名称仅支持输入小写字母、数字、连字符，小写字母开头结尾，不超过15个字符')
276	      return false
277	    }
278	  }
279	  if (hasDuplicateProperty(ports, 'containerPort')) {
280	    message.error('端口配置的容器端口存在重复')
281	    return false
282	  }
283	  if (hasDuplicateProperty(ports, 'name')) {
284	    message.error('端口配置的端口名存在重复')
285	    return false
286	  }
287	  return true
288	}
289	
290	// 校验镜像必填
291	const validateImageConfig = (container: any) => {
292	  const imageConfig = container.imageConfig || {}
293	  const cascader = imageConfig.imageCascader
294	
295	  // 需要选择镜像仓库和镜像名称
296	  if (!Array.isArray(cascader) || cascader.length < 2 || !cascader[0] || !cascader[1]) {
297	    message.error('请选择镜像')
298	    return false
299	  }
300	
301	  return true
302	}
303	
304	const validateResources = (container: any) => {
305	  if (!container.cpu) {
306	    message.error('请输入cpu')
307	    return false
308	  }
309	  if (Number(container.cpu) < 0.1) {
310	    message.error('CPU最小值为0.1')
311	    return false
312	  }
313	  if (!/^(\d+)(\.\d)?$/.test(String(container.cpu))) {
314	    message.error('CPU只支持小数点后一位')
315	    return false
316	  }
317	  if (!container.memory) {
318	    message.error('请输入内存')
319	    return false
320	  }
321	  if (Number(container.memory) < 0.1) {
322	    message.error('内存最小值为0.1')
323	    return false
324	  }
325	  if (container.gpuName && !container.gpu) {
326	    message.error('请输入GPU数量')
327	    return false
328	  }
329	  if (container.gpu) {
330	    if (Number(container.gpu) < 1) {
331	      message.error('GPU最小值为1')
332	      return false
333	    }
334	    if (!Number.isInteger(Number(container.gpu))) {
335	      message.error('GPU数量必须为正整数')
336	      return false
337	    }
338	  }
339	  return true
340	}
341	
342	const validateStorage = (rows: any[]) => {
343	  for (const [index, item] of rows.entries()) {
344	    if (item.storageType === 'tdsc') {
345	      const arr = Array.isArray(item.storagePoolId) ? item.storagePoolId : []
346	      if (!arr[0]) {
347	        message.error(`请完善第${index + 1}个数据卷的配置：选择存储池`)
348	        return false
349	      }
350	      if (arr.length < 2 || !arr[1]) {
351	        message.error(`请完善第${index + 1}个数据卷的配置：选择网盘路径`)
352	        return false
353	      }
354	      if (!item.mountPath) {
355	        message.error(`请完善第${index + 1}个数据卷的配置：输入挂载路径`)
356	        return false
357	      }
358	    } else if (item.storageType === 'hostPath') {
359	      if (!item.storagePath || !item.mountPath) {
360	        message.error(`请完善第${index + 1}个数据卷的配置：填写本地路径和挂载路径`)
361	        return false
362	      }
363	    }
364	  }
365	  return true
366	}
367	
368	const hasDuplicateTaskNames = (tasks: any[], key: string) => {
369	  const seen = new Set()
370	  for (const task of tasks) {
371	    const value = task[key]
372	    if (typeof value === 'string') {
373	      if (seen.has(value)) return true
374	      seen.add(value)
375	    }
376	  }
377	  return false
378	}
379	
380	const hasDuplicateContainerPorts = (containers: any[]) => {
381	  const seenNames = new Set()
382	  const seenPorts = new Set()
383	  for (const container of containers) {
384	    if (!Array.isArray(container.ports)) continue
385	    for (const port of container.ports) {
386	      if (port.name && seenNames.has(port.name)) return true
387	      if (port.containerPort && seenPorts.has(port.containerPort)) return true
388	    }
389	    for (const port of container.ports) {
390	      if (port.name) seenNames.add(port.name)
391	      if (port.containerPort) seenPorts.add(port.containerPort)
392	    }
393	  }
394	  return false
395	}
396	
397	const handleSubmit = async () => {
398	  const nameRegex = /^(?=[a-z])[a-z0-9-]{1,63}$/
399	
400	  if (!formState.value.name) {
401	    message.error('请输入模型名称')
402	    return
403	  }
404	  if (!nameRegex.test(formState.value.name)) {
405	    message.error('模型名称仅支持小写字母、数字、连字符，小写字母开头，不超过63个字符')
406	    return
407	  }
408	  if (!formState.value.clusterCode) {
409	    message.error('请选择集群')
410	    return
411	  }
412	  if (!formState.value.queueName) {
413	    message.error('请选择队列')
414	    return
415	  }
416	  if (formState.value.modelPort === null || Number(formState.value.modelPort) < 1 || Number(formState.value.modelPort) > 65535) {
417	    message.error('模型端口范围为1-65535')
418	    return
419	  }
420	  const replicasNum = Number(formState.value.replicas)
421	  if (
422	    formState.value.replicas === null ||
423	    formState.value.replicas === undefined ||
424	    replicasNum < 0 ||
425	    !Number.isInteger(replicasNum) ||
426	    replicasNum > 10000
427	  ) {
428	    message.error('服务数量需为 0~10000 的整数')
429	    return
430	  }
431	  // 最大重试次数：1~10 的正整数
432	  const maxRetryNum = Number(formState.value.maxRetry)
433	  if (
434	    formState.value.maxRetry === null ||
435	    formState.value.maxRetry === undefined ||
436	    !Number.isInteger(maxRetryNum) ||
437	    maxRetryNum < 1 ||
438	    maxRetryNum > 10
439	  ) {
440	    message.error('最大重试次数需为 1~10 的正整数')
441	    return
442	  }
443	  // 最小启动数量：1~10 的正整数
444	  const minAvailableNum = Number(formState.value.minAvailable)
445	  if (
446	    formState.value.minAvailable === null ||
447	    formState.value.minAvailable === undefined ||
448	    !Number.isInteger(minAvailableNum) ||
449	    minAvailableNum < 1 ||
450	    minAvailableNum > 10
451	  ) {
452	    message.error('最小启动数量需为 1~10 的正整数')
453	    return
454	  }
455	
456	  if (!validateKeyValue(formState.value.labelData, '标签') || !validateKeyValue(formState.value.annotateData, '注解')) {
457	    return
458	  }
459	
460	  await basicRef.value?.validate()
461	  await exampleRef.value?.validate()
462	
463	  const params: any = JSON.parse(JSON.stringify(formState.value))
464	
465	  params.labels = {}
466	  params.labelData.forEach((item: any) => {
467	    if (item.key) params.labels[item.key] = item.value
468	  })
469	
470	  params.annotations = {}
471	  params.annotateData.forEach((item: any) => {
472	    if (item.key) params.annotations[item.key] = item.value
473	  })
474	
475	  params.plugins = {}
476	  params.pluginsData.forEach((item: any) => {
477	    if (item.key) params.plugins[item.key] = item.value
478	  })
479	
480	  if (hasDuplicateTaskNames(params.tasks, 'name')) {
481	    message.error('实例名称不允许重复')
482	    return
483	  }
484	
485	  for (const task of params.tasks) {
486	    if (!task.name || !nameRegex.test(task.name)) {
487	      message.error('请检查实例名称，需满足DNS规范')
488	      return
489	    }
490	    if (!task.replicas) {
491	      message.error('请输入副本数')
492	      return
493	    }
494	    if (hasDuplicateTaskNames(task.containers, 'name')) {
495	      message.error('容器名称不允许重复')
496	      return
497	    }
498	
499	    for (const container of task.containers) {
500	      if (!container.name || !nameRegex.test(container.name)) {
501	        message.error('请检查容器名称，需满足DNS规范')
502	        return
503	      }
504	      if (!validateImageConfig(container)) return
505	      if (!validateEnvironmentVars(container.environmentVarsData)) return
506	      if (!validatePorts(container.ports)) return
507	      if (!validateResources(container)) return
508	      if (!validateStorage(container.storage)) return
509	
510	      container.environmentVars = {}
511	      container.environmentVarsData.forEach((item: any) => {
512	        if (item.key) container.environmentVars[item.key] = item.value
513	      })
514	
515	      const shell = (container.commandShell || '').trim()
516	      const cmd = (container.commandText || '').trim()
517	      container.command = shell && cmd ? [shell, '-c', cmd] : []
518	
519	      if (container.gpuRatio) container.gpuRatio = Number(container.gpuRatio) / 100
520	
521	      container.cpu = container.cpu !== '' ? String(container.cpu) : ''
522	      container.memory = container.memory !== '' ? String(container.memory) : ''
523	      container.gpu = container.gpu !== '' ? String(container.gpu) : ''
524	
525	      container.imageConfig.project = container.imageConfig.imageCascader[0]
526	      container.imageConfig.imageName = container.imageConfig.imageCascader[1]
527	      container.imageConfig.domain = params.imageRepoList?.find((item: any) => item.id === container.imageConfig.repositoryId)?.domain || ''
528	
529	      container.storage = container.storage.map((item: any) => {
530	        if (item.storageType === 'tdsc') {
531	          const arr = Array.isArray(item.storagePoolId) ? item.storagePoolId : []
532	          let storagePath = ''
533	          if (arr.length > 1) {
534	            const last = arr[arr.length - 1]
535	            storagePath = last.replace(/^\/?/, '/').replace(/\/$/, '')
536	          }
537	          return {
538	            storagePoolId: arr[0] || 0,
539	            storageType: 'tdsc',
540	            storagePath,
541	            mountPath: item.mountPath,
542	          }
543	        }
544	        if (item.storageType === 'hostPath') {
545	          let storagePath = item.storagePath || ''
546	          if (storagePath && !storagePath.startsWith('/')) storagePath = `/${storagePath}`
547	          return {
548	            storagePoolId: 0,
549	            storageType: 'hostPath',
550	            storagePath,
551	            mountPath: item.mountPath,
552	          }
553	        }
554	        return {
555	          storagePoolId: 0,
556	          storageType: '',
557	          storagePath: '',
558	          mountPath: '',
559	        }
560	      })
561	    }
562	
563	    if (hasDuplicateContainerPorts(task.containers)) {
564	      message.error('端口配置中同实例下容器端口与端口名均不可重复')
565	      return
566	    }
567	  }
568	
569	  // 任务数量需大于等于最小启动数（实例数校验）
570	  const minAvailableVal = Number(formState.value.minAvailable)
571	  if (minAvailableVal && formState.value.tasks.length < minAvailableVal) {
572	    message.error('最小启动数量需小于等于所有任务的副本数总和')
573	    return
574	  }
575	
576	  const payload = {
577	    modelName: params.name,
578	    inferenceFramework: params.inferenceFramework,
579	    modelPort: Number(params.modelPort),
580	    replicas: Number(params.replicas),
581	    servingType: params.servingType || 'VolcanoJob',
582	    clusterCode: params.clusterCode,
583	    queueName: params.queueName,
584	    volcanoJob: {
585	      labels: params.labels,
586	      annotations: params.annotations,
587	      maxRetry: Number(params.maxRetry),
588	      minAvailable: Number(params.minAvailable),
589	      plugins: params.plugins,
590	      tasks: params.tasks,
591	    },
592	  }
593	
594	  permissionStore.spinning = true
595	  try {
596	    const res: any = route.params.title === '编辑'
597	      ? await updateInferenceServing(permissionStore.curProject, route.query.id, payload)
598	      : await createInferenceServing(permissionStore.curProject, payload)
599	    if (res.code === '00000') {
600	      message.success(route.params.title === '编辑' ? '更新成功' : '创建成功')
601	      router.back()
602	    }
603	  } finally {
604	    permissionStore.spinning = false
605	  }
606	}
607	
608	const handleCancel = () => {
609	  router.back()
610	}
611	</script>
612	
613	<style lang="scss" scoped>
614	.list-content-wrapper {
